def _runs(white, size):
    """All maximal white runs (both directions) as (cells, length)."""
    out = []
    for dr, dc in ((0, 1), (1, 0)):
        for r in range(size):
            for c in range(size):
                if (r, c) not in white:
                    continue
                if (r - dr, c - dc) in white:
                    continue  # not a run start
                cells = []
                rr, cc = r, c
